    Hv = torch.autograd.grad(grad_params, params, grad_outputs=v,
                             retain_graph=True)
    Hv = tuple(Hvi.detach() for Hvi in Hv)
    return torch.cat([Hvi.reshape(-1) for Hvi in Hv])

